code = """import json
import re

# Load the Swift files data
swift_files_data = var_functions.query_db:20

# If it's a file path, read from file
if isinstance(swift_files_data, str) and swift_files_data.endswith('.json'):
    with open(swift_files_data, 'r') as f:
        swift_files_data = json.load(f)

# Create list to store files with copy counts
files_with_copies = []

for file_entry in swift_files_data:
    if 'repo_data_description' in file_entry:
        desc = file_entry['repo_data_description'].lower()
        
        # Extract number of times copied from descriptions
        # Match patterns like "8 times", "10 times", etc.
        match = re.search(r'(\d+) (time|copies|copy)', desc)
        if match:
            copies = int(match.group(1))
            
            # Only include if it's explicitly mentioned as non-binary
            if 'non-binary' in desc:
                files_with_copies.append({
                    'repo_name': file_entry['sample_repo_name'],
                    'file_path': file_entry['sample_path'],
                    'id': file_entry['id'],
                    'copies': copies,
                    'description': desc
                })

# Find file with max copies
if files_with_copies:
    max_copies_file = max(files_with_copies, key=lambda x: x['copies'])
    result = {
        'max_copies': max_copies_file['copies'],
        'repo_name': max_copies_file['repo_name'],
        'file_path': max_copies_file['file_path'],
        'file_id': max_copies_file['id']
    }
else:
    result = {'error': 'No Swift files found with copy information'}

print('__RESULT__:')
print(json.dumps(result))"""

